class Solution:
    def minOperations(self, nums1, nums2):
        s1, s2 = sum(nums1), sum(nums2)
        if s1 == s2:
            return 0
        if s1 < s2:
            nums1, nums2 = nums2, nums1
            s1, s2 = s2, s1
        diff = s1 - s2
        gains = []
        for v in nums1:
            gains.append(v - 1)
        for v in nums2:
            gains.append(6 - v)
        gains.sort(reverse=True)
        ops = 0
        for g in gains:
            if diff <= 0:
                break
            if g <= 0:
                continue
            diff -= g
            ops += 1
        return ops if diff <= 0 else -1

