class Solution:
    def minOperations(self, nums1, nums2):
        s1, s2 = sum(nums1), sum(nums2)
        if s1 < s2:
            nums1, nums2 = nums2, nums1
            s1, s2 = s2, s1
        diff = s1 - s2
        if diff == 0:
            return 0
        bucket = [0] * 6
        for v in nums1:
            if v - 1 > 0:
                bucket[v - 1] += 1
        for v in nums2:
            if 6 - v > 0:
                bucket[6 - v] += 1
        ops = 0
        for g in range(5, 0, -1):
            if diff <= 0:
                break
            take = min(bucket[g], -(-diff // g))
            diff -= take * g
            ops += take
        return ops if diff <= 0 else -1

