var minOperations = function(nums1, nums2) {
    let s1 = nums1.reduce((a, b) => a + b, 0);
    let s2 = nums2.reduce((a, b) => a + b, 0);
    if (s1 < s2) { [nums1, nums2] = [nums2, nums1]; [s1, s2] = [s2, s1]; }
    let diff = s1 - s2;
    if (diff === 0) return 0;
    const bucket = new Array(6).fill(0);
    for (const v of nums1) if (v - 1 > 0) bucket[v - 1]++;
    for (const v of nums2) if (6 - v > 0) bucket[6 - v]++;
    let ops = 0;
    for (let g = 5; g >= 1; g--) {
        if (diff <= 0) break;
        const need = Math.ceil(diff / g);
        const take = Math.min(bucket[g], need);
        diff -= take * g;
        ops += take;
    }
    return diff <= 0 ? ops : -1;
};
